      // if the page is newly created, the page id in the store will no longer start with "new" but the URL will not
      // have been updated yet. This will cause a mismatch between the URL and the store, so we need to update the URL
      const toReplace = isNewEvent ? 'new-event' : 'new';
      const nextPath = pathname.replace(toReplace, pageId);
      navigate(nextPath, { replace: true });
    }
  }, [isNew, isNewEvent, navigate, pageId, pathname]);

  // automatically navigate the users to corresponding panel and focus on corresponding input when undo/redo is triggered
  useAutoNavigation();

  // reset the builder state when the page is unmounted
  useEffect(() => reset, []);

  const defaultPath = isNewEvent ? 'event' : 'design';

