};

type Result = {
  actionPage?: ActionPageDetails;
  isLoading?: boolean;
  isNew: boolean;
  source?: ActionPageDetails;
};

export const useGetEditableActionPage = ({ actionPageId, cloneFrom, type }: Params): Result => {
  const isNew = useMemo(() => actionPageId === 'new', [actionPageId]);

  const { billingAgreements, isLoadingBillingAgreements } = useGetAllBillingAgreements({
    actionPageId: cloneFrom,
    enabled: !!cloneFrom,
    page: 1,
    perPage: 100,
  });

  const { data: currentActionPage, isLoading: isLoadingActionPage } = useGetActionPage(
    {
      actionPageId,
    },
    { enabled: !isNew }
  );

  const { data: source, isLoading: isLoadingSource } = useGetActionPage(
    { actionPageId: cloneFrom },
    { enabled: !!cloneFrom }
  );

  const {
    isClonedLoading,
    newClonedAmountConfig,
    newClonedConfirmationConfig,
    newClonedDesignConfig,
    newClonedFieldConfig,
    newClonedFundConfig,
    newClonedGeneralConfig,
    newClonedPaymentConfig,
    newClonedUpgradeConfig,
  } = useCreateClonedPresets({
    cloneFrom,
    source,
  });

  const clonedActionPage = useMemo(() => {
    if (source && !isClonedLoading) {
      try {
        const actionPageSource: ActionPageDetails = JSON.parse(JSON.stringify(source));

        return {
          ...actionPageSource,
          amountConfigurationId:
            newClonedAmountConfig?.id ?? actionPageSource.amountConfigurationId,
          billingAgreementIds: billingAgreements?.map((ba) => ba.id),
          campaign: undefined,
          confirmationConfigurationId:
            newClonedConfirmationConfig?.id ?? actionPageSource.confirmationConfigurationId,
          designConfigurationId:
            newClonedDesignConfig?.id ?? actionPageSource.designConfigurationId,
          fieldConfigurationId: newClonedFieldConfig?.id ?? actionPageSource.fieldConfigurationId,
          fundConfigurationId: newClonedFundConfig?.id ?? actionPageSource.fundConfigurationId,
          generalConfigurationId:
            newClonedGeneralConfig?.id ?? actionPageSource.generalConfigurationId,
          id: 'new',
          name: `${source.name} - Clone`,
          paymentConfigurationId:
            newClonedPaymentConfig?.id ?? actionPageSource.paymentConfigurationId,
          productPositionsAttributes: actionPageSource.productPositionsAttributes?.map((att) =>
            omit(att, ['id'])
          ),
          slug: v4(),
          upgradeConfigurationId:
            newClonedUpgradeConfig?.id ?? actionPageSource.upgradeConfigurationId,
        };
      } catch (_err) {
        console.warn('Unable to clone action page');
      }
    }

    return undefined;
  }, [
    billingAgreements,
    isClonedLoading,
    newClonedAmountConfig?.id,
    newClonedConfirmationConfig?.id,
    newClonedDesignConfig?.id,
    newClonedFieldConfig?.id,
    newClonedFundConfig?.id,
    newClonedGeneralConfig?.id,
    newClonedPaymentConfig?.id,
    newClonedUpgradeConfig?.id,
    source,
  ]);

  const { actionPage: newActionPage } = useCreateEditableActionPage({
    enabled: isNew,
    type,
  });

  const actionPage = useMemo(
    () => (cloneFrom ? clonedActionPage : isNew ? newActionPage : currentActionPage),
    [cloneFrom, clonedActionPage, isNew, newActionPage, currentActionPage]
  );

  const isLoading = useMemo(
    () => isLoadingActionPage || isLoadingBillingAgreements || isLoadingSource || isClonedLoading,
    [isClonedLoading, isLoadingActionPage, isLoadingBillingAgreements, isLoadingSource]
  );

  return useMemo(
    () => ({ actionPage, isLoading, isNew, source }),
    [actionPage, isLoading, isNew, source]
  );
};

